prefab_ui/css.py:
"""CSS utilities for Tailwind class composition.

Helpers for building css_class values without repeating variant prefixes.

Pseudo-state helpers prefix each space-separated class:

```python
from prefab_ui.css import Hover, FocusVisible

css_class=["p-4 border-0", Hover("bg-blue-500 scale-105")]
# → "p-4 border-0 hover:bg-blue-500 hover:scale-105"

css_class=["ring-0 border-0", FocusVisible("border-b border-border")]
# → "ring-0 border-0 focus-visible:border-b focus-visible:border-border"
```

Responsive maps Tailwind breakpoints to values:

```python
from prefab_ui.css import Responsive

Grid(columns=Responsive(default=1, md=2, lg=3))
Button("Go", css_class=Responsive(default="w-full", md="w-auto"))
```
"""

from __future__ import annotations

from typing import Any

# ── Responsive ─────────────────────────────────────────────────────────

_BREAKPOINTS = ("default", "sm", "md", "lg", "xl", "2xl")

_BreakpointFormatter = Any  # Callable[[Any], str] — avoid import complexity


class Responsive:
    """Breakpoint-aware values for responsive layouts.

    Maps Tailwind breakpoints to values. At compile time, each entry is
    prefixed with its breakpoint (`default` emits unprefixed classes).

    **Usage:**

    ```python
    Grid(columns=Responsive(default=1, md=2, lg=3))
    Row(gap=Responsive(default=2, md=4))
    Button("Go", css_class=Responsive(default="w-full", md="w-auto"))
    ```
    """

    __slots__ = ("_values",)

    def __init__(self, **kwargs: Any) -> None:
        invalid = set(kwargs) - set(_BREAKPOINTS)
        if invalid:
            raise ValueError(
                f"Invalid breakpoint(s): {', '.join(sorted(invalid))}. "
                f"Valid breakpoints: {', '.join(_BREAKPOINTS)}"
            )
        if not kwargs:
            raise ValueError("Responsive() requires at least one breakpoint value")
        self._values: dict[str, Any] = kwargs

    def __repr__(self) -> str:
        inner = ", ".join(f"{k}={v!r}" for k, v in self._values.items())
        return f"Responsive({inner})"

    def __eq__(self, other: object) -> bool:
        if isinstance(other, Responsive):
            return self._values == other._values
        return NotImplemented

    @property
    def values(self) -> dict[str, Any]:
        return dict(self._values)

    def compile_css(self, formatter: _BreakpointFormatter) -> str:
        """Compile to a space-separated Tailwind class string.

        The *formatter* is called once per breakpoint entry and should
        return one or more CSS utility classes for the given value.
        """
        parts: list[str] = []
        for bp in _BREAKPOINTS:
            if bp not in self._values:
                continue
            classes = formatter(self._values[bp])
            if not classes:
                continue
            if bp == "default":
                parts.append(classes)
            else:
                for cls in classes.split():
                    parts.append(f"{bp}:{cls}")
        return " ".join(parts)


# ── Variant helpers ───────────────────────────────────────────────────


def _prefixed(prefix: str, classes: str) -> str:
    """Prefix each space-separated class with a Tailwind variant."""
    return " ".join(f"{prefix}:{cls}" for cls in classes.split())


def Hover(classes: str) -> str:
    """Prefix classes with `hover:`.

    **Example:**

    ```python
    css_class=["p-4", Hover("bg-blue-500 scale-105")]
    # → "p-4 hover:bg-blue-500 hover:scale-105"
    ```
    """
    return _prefixed("hover", classes)


def Focus(classes: str) -> str:
    """Prefix classes with `focus:`."""
    return _prefixed("focus", classes)


def FocusVisible(classes: str) -> str:
    """Prefix classes with `focus-visible:`."""
    return _prefixed("focus-visible", classes)


def FocusWithin(classes: str) -> str:
    """Prefix classes with `focus-within:`."""
    return _prefixed("focus-within", classes)


def Active(classes: str) -> str:
    """Prefix classes with `active:`."""
    return _prefixed("active", classes)


def Disabled(classes: str) -> str:
    """Prefix classes with `disabled:`."""
    return _prefixed("disabled", classes)


# ── Breakpoint helpers ────────────────────────────────────────────────


def Sm(classes: str) -> str:
    """Prefix classes with `sm:` (≥640px)."""
    return _prefixed("sm", classes)


def Md(classes: str) -> str:
    """Prefix classes with `md:` (≥768px)."""
    return _prefixed("md", classes)


def Lg(classes: str) -> str:
    """Prefix classes with `lg:` (≥1024px)."""
    return _prefixed("lg", classes)


def Xl(classes: str) -> str:
    """Prefix classes with `xl:` (≥1280px)."""
    return _prefixed("xl", classes)


def Xxl(classes: str) -> str:
    """Prefix classes with `2xl:` (≥1536px)."""
    return _prefixed("2xl", classes)

prefab_ui/components/base.py:
"""Base classes for MCP Apps UI components."""

from __future__ import annotations

import contextlib
import re
from collections.abc import Generator
from contextlib import contextmanager
from contextvars import ContextVar
from typing import Annotated, Any, ClassVar, Literal, cast

from pydantic import (
    BaseModel,
    BeforeValidator,
    Field,
    model_serializer,
    model_validator,
)
from typing_extensions import Self

from prefab_ui.css import Responsive
from prefab_ui.rx import Rx, _coerce_rx, _generate_key, _sanitize_floats

_component_stack: ContextVar[list[ContainerComponent] | None] = ContextVar(
    "_component_stack", default=None
)
_defer_next_component: ContextVar[bool] = ContextVar(
    "_defer_next_component", default=False
)


@contextmanager
def defer() -> Generator[None, None, None]:
    """Create components without attaching them to the current parent.

    Components created inside a `defer()` block are **not** automatically
    appended as children to any enclosing context manager. Use
    `insert()` later to place them in the tree:

    ```python
    with Column() as outer:
        with defer():
            sidebar = Column()
            with sidebar:
                Text("child of sidebar, not outer")
        insert(sidebar)

    assert len(outer.children) == 2
    ```
    """
    saved = _component_stack.get()
    _component_stack.set(None)
    try:
        yield
    finally:
        _component_stack.set(saved)


def insert(component: Component) -> Component:
    """Insert a deferred component into the current parent context.

    Use this to place a component that was created outside the tree
    (either before any `with` block or inside a `defer()` block)
    as a child of the current container:

    ```python
    volume = Slider(value=75, defer=True)

    with Column():
        Text(f"{volume.rx.number()}%")
        insert(volume)  # volume becomes a child of Column here
    ```

    Raises `RuntimeError` if called outside a container context
    or if the component is already a child of another container.
    """
    stack = _component_stack.get() or []
    if not stack:
        raise RuntimeError(
            "insert() must be called inside a container context manager "
            "(e.g. inside a `with Column():` block)"
        )

    # Check if already attached to a parent
    for parent in stack:
        if any(c is component for c in parent.children):
            raise RuntimeError(
                "This component is already a child of a container. "
                "Use model_copy() to create an independent copy."
            )

    stack[-1].children.append(component)
    return component


# ── Gap / Align / Justify ──────────────────────────────────────────────


def _coerce_gap(v: Any) -> int | tuple[int | None, int | None] | Responsive | None:
    """Normalize gap values: None, int, (int,), (x, y), or Responsive."""
    if v is None or isinstance(v, Responsive):
        return v
    if isinstance(v, (list, tuple)):
        if len(v) == 1:
            return int(v[0])
        if len(v) == 2:
            x = int(v[0]) if v[0] is not None else None
            y = int(v[1]) if v[1] is not None else None
            return (x, y)
        raise ValueError("gap must have 1 or 2 values")
    return int(v)


Gap = Annotated[
    int | tuple[int | None, int | None] | Responsive | None,
    BeforeValidator(_coerce_gap),
]

Align = Literal["start", "center", "end", "stretch", "baseline"] | None

Justify = (
    Literal["start", "center", "end", "between", "around", "evenly", "stretch"] | None
)


# ── Layout class compilation ───────────────────────────────────────────


def _gap_classes(gap: int | tuple[int | None, int | None]) -> str:
    """Return Tailwind gap classes for a plain gap value."""
    if isinstance(gap, tuple):
        parts: list[str] = []
        x, y = gap
        if x is not None:
            parts.append(f"gap-x-{x}")
        if y is not None:
            parts.append(f"gap-y-{y}")
        return " ".join(parts)
    return f"gap-{gap}"


def _compile_layout_classes(
    *,
    gap: int | tuple[int | None, int | None] | Responsive | None = None,
    columns: int | dict[str, int] | Responsive | None = None,
    align: str | None = None,
    justify: str | None = None,
) -> str | None:
    """Compile layout kwargs to a Tailwind class string."""
    parts: list[str] = []

    # Gap
    if gap is not None:
        if isinstance(gap, Responsive):
            parts.append(gap.compile_css(_gap_classes))
        else:
            parts.append(_gap_classes(gap))

    # Columns
    if columns is not None:
        if isinstance(columns, Responsive):
            parts.append(columns.compile_css(lambda n: f"grid-cols-{n}"))
        elif isinstance(columns, dict):
            parts.append(Responsive(**columns).compile_css(lambda n: f"grid-cols-{n}"))
        else:
            parts.append(f"grid-cols-{columns}")

    if align is not None:
        parts.append(f"items-{align}")
    if justify is not None:
        parts.append(f"justify-{justify}")
    return " ".join(parts) if parts else None


def _merge_css_classes(*classes: str | None) -> str | None:
    """Merge multiple class strings, returning None if empty."""
    merged = " ".join(c for c in classes if c)
    return merged or None


def _coerce_css_class(v: Any) -> str | None:
    """Compile css_class to a flat string.

    Accepts a plain string, a Responsive object, or a list mixing both.
    """
    if v is None:
        return None
    if isinstance(v, list):
        parts: list[str] = []
        for item in v:
            if isinstance(item, Responsive):
                compiled = item.compile_css(lambda s: str(s))
                if compiled:
                    parts.append(compiled)
            elif item:
                parts.append(str(item))
        return " ".join(parts) or None
    if isinstance(v, Responsive):
        compiled = v.compile_css(lambda s: str(s))
        return compiled or None
    return str(v)


_VALID_STATE_KEY = re.compile(r"^[a-zA-Z_$][a-zA-Z0-9_.$]*$")


class StatefulMixin:
    """Mixin for components that support reactive state binding via `.rx`.

    Stateful components (Slider, Input, Checkbox, etc.) inherit from this
    mixin to gain the `.rx` property, which returns an `Rx` object
    serializing to `{{ name }}` for template expressions.

    Subclasses narrow the `value` type (e.g. `bool` for Checkbox,
    `str | None` for Tabs).
    """

    _auto_name: ClassVar[str]
    name: str | None
    value: Any

    def __init_subclass__(cls, **kwargs: Any) -> None:
        super().__init_subclass__(**kwargs)

    def _validate_state_key_name(self) -> None:
        """Raise ValueError if name is not a valid expression identifier."""
        if self.name is None or "{{" in self.name:
            return
        if not _VALID_STATE_KEY.match(self.name):
            raise ValueError(
                f"Invalid state key name {self.name!r}: must be a valid identifier "
                f"(letters, digits, underscores — no hyphens). "
                f"'{{{{ {self.name} }}}}' would be parsed as arithmetic."
            )

    @property
    def rx(self) -> Rx:
        """Reactive reference to this component's state value.

        Returns an `Rx` object that serializes to `{{ key }}` and can
        be passed to any string-typed component field or used in f-strings.
        """
        if self.name is None:
            raise ValueError(
                f"{type(self).__name__}.rx requires a name — "
                f"set _auto_name on the class or pass name= explicitly"
            )
        return Rx(self.name)


class Component(BaseModel):
    """Base class for all UI components.

    Components serialize to JSON via `to_json()` for the React renderer.
    When created inside a `ContainerComponent` context manager, they
    automatically append themselves to the parent's children list.

    Alternatively, pass `parent=<container>` to attach to a specific
    container without using a context manager:

    ```python
    root = Column(gap=4)
    Heading("Sales Report", parent=root)
    Text("Q3 results", parent=root)
    ```
    """

    model_config = {"populate_by_name": True, "arbitrary_types_allowed": True}

    _auto_name: ClassVar[str | None] = None
    """Subclasses set this to a prefix string (e.g. `"slider"`) to opt in
    to automatic name generation.  When set, components without an explicit
    `name` receive a deterministic sequential key like `slider-1`."""

    id: str | None = Field(
        default=None,
        description="HTML id attribute for CSS targeting. Applied to the outermost element.",
    )

    css_class: Annotated[str | None, BeforeValidator(_coerce_css_class)] = Field(
        default=None,
        alias="cssClass",
        description="CSS/Tailwind classes for styling. Accepts a Responsive() for breakpoint-aware classes.",
    )

    on_mount: Any | None = Field(
        default=None,
        alias="onMount",
        description="Action(s) to execute when this component mounts.",
    )

    def __init__(self, /, **kwargs: Any) -> None:
        parent = kwargs.pop("parent", None)
        if parent is not None:
            if not isinstance(parent, ContainerComponent):
                raise TypeError(
                    f"parent must be a container component like Column or Row, "
                    f"got {type(parent).__name__}"
                )
            if kwargs.get("defer", False):
                raise ValueError(
                    "Cannot use parent= and defer=True together — "
                    "parent= attaches immediately, defer=True prevents attachment"
                )
        super().__init__(**kwargs)
        if parent is not None:
            # Undo stack auto-attach that model_post_init may have done
            stack = _component_stack.get() or []
            if stack:
                with contextlib.suppress(ValueError):
                    stack[-1].children.remove(self)
            parent.children.append(self)

    @model_validator(mode="before")
    @classmethod
    def _extract_defer(cls, data: Any) -> Any:
        """Extract the `defer` kwarg and unwrap Rx names before validation."""
        if isinstance(data, dict):
            if data.pop("defer", False):
                _defer_next_component.set(True)
            # Unwrap Rx name to bare key string for state path binding
            name = data.get("name")
            if isinstance(name, Rx):
                data["name"] = name.key
        return data

    @model_serializer(mode="wrap")
    def _serialize_rx(self, handler: Any) -> dict[str, Any]:
        """Resolve any Rx values to `{{ }}` strings at serialization time."""
        return _coerce_rx(handler(self))  # type: ignore[return-value]  # ty:ignore[invalid-return-type]

    def model_post_init(self, __context: Any) -> None:
        # Auto-generate name and validate for stateful components
        if isinstance(self, StatefulMixin):
            if self.name is None:
                object.__setattr__(self, "name", _generate_key(self._auto_name))
            self._validate_state_key_name()

        # Skip auto-attach when defer=True was passed
        if _defer_next_component.get():
            _defer_next_component.set(False)
            return

        stack = _component_stack.get() or []
        if stack:
            stack[-1].children.append(self)

    def to_json(self) -> dict[str, Any]:
        """Serialize to JSON format for the React renderer.

        Produces a JSON object with `type` set to the class name plus
        props, with `None` values excluded. Children are serialized recursively.
        """
        data = self.model_dump(by_alias=True, exclude_none=True)
        return cast(dict[str, Any], _sanitize_floats(data))


class ContainerComponent(Component):
    """Component that can contain child components.

    Use as a context manager to build nested layouts:

    ```python
    with Column():
        Text("hello")
        Text("world")
    ```
    """

    children: list[Component] = Field(default_factory=list)
    let: dict[str, Any] | None = Field(
        default=None,
        description="Scoped bindings available to children. Values are template strings.",
    )

    def model_post_init(self, __context: Any) -> None:
        # When children= is passed explicitly, those children were already
        # auto-attached to the *outer* stack parent during their own __init__.
        # Remove them from that parent so they only belong to this component.
        stack = _component_stack.get() or []
        if stack and self.children:
            parent_children = stack[-1].children
            for child in self.children:
                with contextlib.suppress(ValueError):
                    parent_children.remove(child)
        super().model_post_init(__context)

    def __enter__(self) -> Self:
        stack = _component_stack.get() or []
        _component_stack.set([*stack, self])
        return self

    def __exit__(self, *args: Any) -> None:
        stack = _component_stack.get() or []
        _component_stack.set(stack[:-1])

    def to_json(self) -> dict[str, Any]:
        d = super().to_json()
        # model_dump includes children=[] (not None), so always replace with
        # recursive serialization or remove the key when empty.
        d.pop("children", None)
        if self.children:
            d["children"] = _serialize_children(self.children)
        return d


def _to_case(node: Component) -> dict[str, Any]:
    """Convert an If or Elif node to a Condition case entry."""
    condition = str(getattr(node, "condition", ""))
    stripped = condition.strip()
    if not (stripped.startswith("{{") and stripped.endswith("}}")):
        condition = f"{{{{ {condition} }}}}"
    case: dict[str, Any] = {"when": condition}
    children = getattr(node, "children", [])
    if children:
        case["children"] = _serialize_children(children)
    return case


def _serialize_children(children: list[Component]) -> list[dict[str, Any]]:
    """Serialize children, grouping If/Elif/Else chains into Condition nodes."""
    result: list[dict[str, Any]] = []
    i = 0
    while i < len(children):
        child = children[i]
        child_type = getattr(child, "type", None)

        if child_type == "If":
            cases: list[dict[str, Any]] = [_to_case(child)]
            else_children: list[dict[str, Any]] | None = None
            i += 1
            while i < len(children):
                t = getattr(children[i], "type", None)
                if t == "Elif":
                    cases.append(_to_case(children[i]))
                    i += 1
                elif t == "Else":
                    inner = getattr(children[i], "children", [])
                    else_children = _serialize_children(inner)
                    i += 1
                    break
                else:
                    break
            node: dict[str, Any] = {"type": "Condition", "cases": cases}
            if else_children:
                node["else"] = else_children
            result.append(node)

        elif child_type in ("Elif", "Else"):
            raise ValueError(
                f"{child_type} without preceding If — "
                f"Elif and Else must immediately follow an If or Elif"
            )

        else:
            result.append(child.to_json())
            i += 1

    return result

prefab_ui/actions/fetch.py:
"""Client-side HTTP fetch action.

Makes HTTP requests directly from the browser using `fetch()`. Use this
for REST API calls, loading external data, form submissions — anything
that talks HTTP without going through an MCP server.

**Example:**

```python
from prefab_ui.components import Button
from prefab_ui.actions import Fetch, SetState, ShowToast
from prefab_ui.rx import RESULT

Button("Load Users", on_click=Fetch.get(
    "/api/users",
    on_success=SetState("users", RESULT),
    on_error=ShowToast("{{ $error }}", variant="error"),
))
```
"""

from __future__ import annotations

from typing import Any, Literal
from urllib.parse import quote

from pydantic import Field

from prefab_ui.actions.base import Action
from prefab_ui.rx import RxStr

Method = Literal["GET", "POST", "PUT", "PATCH", "DELETE"]


class Fetch(Action):
    """Make an HTTP request from the browser.

    The parsed response body is available as `$result` in `on_success`
    callbacks. JSON responses are parsed automatically; other content types
    return the raw text. Non-2xx responses trigger `on_error` with the
    status text as `$error`.
    """

    action: Literal["fetch"] = "fetch"
    url: RxStr = Field(description="URL to fetch. Supports `{{ key }}` interpolation.")
    method: Method = Field(default="GET", description="HTTP method.")
    headers: dict[str, str] | None = Field(
        default=None,
        description="Request headers.",
    )
    body: dict[str, Any] | str | None = Field(
        default=None,
        description="Request body. Dicts are JSON-serialized automatically.",
    )

    def __init__(self, url: RxStr, **kwargs: Any) -> None:
        kwargs["url"] = url
        super().__init__(**kwargs)

    @classmethod
    def get(
        cls,
        url: str,
        *,
        params: dict[str, str] | None = None,
        **kwargs: Any,
    ) -> Fetch:
        """GET request. `params` are appended as a query string.

        Values are kept raw so `{{ key }}` interpolation survives to the
        renderer. Only param *names* are percent-encoded.
        """
        if params:
            sep = "&" if "?" in url else "?"
            qs = "&".join(f"{quote(k, safe='')}={v}" for k, v in params.items())
            url = f"{url}{sep}{qs}"
        return cls(url, method="GET", **kwargs)

    @classmethod
    def post(
        cls, url: str, *, body: dict[str, Any] | str | None = None, **kwargs: Any
    ) -> Fetch:
        """POST request with an optional body."""
        return cls(url, method="POST", body=body, **kwargs)

    @classmethod
    def put(
        cls, url: str, *, body: dict[str, Any] | str | None = None, **kwargs: Any
    ) -> Fetch:
        """PUT request with an optional body."""
        return cls(url, method="PUT", body=body, **kwargs)

    @classmethod
    def patch(
        cls, url: str, *, body: dict[str, Any] | str | None = None, **kwargs: Any
    ) -> Fetch:
        """PATCH request with an optional body."""
        return cls(url, method="PATCH", body=body, **kwargs)

    @classmethod
    def delete(cls, url: str, **kwargs: Any) -> Fetch:
        """DELETE request."""
        return cls(url, method="DELETE", **kwargs)

prefab_ui/actions/state.py:
"""Client-side state management actions."""

from __future__ import annotations

import re
from typing import Any, Literal

from pydantic import Field, field_validator

from prefab_ui.actions.base import Action
from prefab_ui.components.base import StatefulMixin
from prefab_ui.rx import Rx

_KEY_RE = re.compile(r"^[a-zA-Z_][a-zA-Z0-9_]*$")

_KeyLike = str | Rx | StatefulMixin


def _resolve_key(key: _KeyLike) -> str:
    """Extract a string state key from a str, Rx, or stateful component."""
    if isinstance(key, StatefulMixin):
        return key.rx.key
    if isinstance(key, Rx):
        return key.key
    return key


def _validate_path(path: str) -> str:
    """Validate a state key or dot-path.

    Each segment must be either a valid identifier (`[a-zA-Z_][a-zA-Z0-9_]*`)
    or a pure integer (array index). Periods delimit segments.

    Paths containing `{{ }}` template expressions are passed through
    without validation — the renderer resolves them at runtime.
    """
    if "{{" in path:
        return path
    for segment in path.split("."):
        if segment.isdigit():
            continue
        if not _KEY_RE.match(segment):
            raise ValueError(
                f"Invalid path segment: {segment!r}. "
                "Segments must be identifiers ([a-zA-Z_][a-zA-Z0-9_]*) or integers."
            )
    return path


class SetState(Action):
    """Set a client-side state variable. No server round-trip.

    The `key` supports dot-paths for nested updates:

    ```python
    SetState("todos.0.done", True)   # deep-update into a list
    ```
    """

    action: Literal["setState"] = "setState"
    key: str = Field(description="State key or dot-path to set")
    value: Any = Field(description="Value to set.")

    @field_validator("key")
    @classmethod
    def _validate_key(cls, v: str) -> str:
        return _validate_path(v)

    def __init__(self, key: _KeyLike, value: Any, **kwargs: Any) -> None:
        kwargs["key"] = _resolve_key(key)
        kwargs["value"] = value
        super().__init__(**kwargs)


class ToggleState(Action):
    """Flip a boolean state variable. No server round-trip."""

    action: Literal["toggleState"] = "toggleState"
    key: str = Field(description="State key or dot-path to toggle")

    @field_validator("key")
    @classmethod
    def _validate_key(cls, v: str) -> str:
        return _validate_path(v)

    def __init__(self, key: _KeyLike, **kwargs: Any) -> None:
        kwargs["key"] = _resolve_key(key)
        super().__init__(**kwargs)


class AppendState(Action):
    """Append a value to a state array.

    Appends to the end by default. Pass `index` to insert at a specific
    position (supports negative indices, e.g. `index=0` to prepend).

    If the key doesn't exist yet, creates a new single-element array.
    """

    action: Literal["appendState"] = "appendState"
    key: str = Field(description="State key or dot-path to the array")
